// benchFixture is a SYNTHETIC multi-page fixture (D8) — deterministic, sufficient for
// regression numbers, and not coupled to real-PDF sourcing. Generated by
// TestCorpusRegenerate via buildBenchCorpusPDF.
const benchFixture = "bench/synthetic-multipage.pdf"

func benchReader(b *testing.B) *Reader {
	b.Helper()
	data, err := os.ReadFile(corpusPath(benchFixture))
	if err != nil {
		b.Fatalf("read bench fixture: %v", err)
	}
	r, err := OpenBytes(data)
	if err != nil {
		b.Fatalf("open bench fixture: %v", err)
	}
	return r
}

// Throughput baseline only (no ReportAllocs); for alloc tracking see BenchmarkCJKColdOpenExtract.
func BenchmarkGetPlainText(b *testing.B) {
	r := benchReader(b)
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		rd, err := r.GetPlainText(context.Background())
		if err != nil {
			b.Fatal(err)
		}
		_, _ = io.Copy(io.Discard, rd)
	}
}

// cjkBenchFixture is the real 22-page Traditional Chinese fixture; it exercises
// the ToUnicode-CMap decode path that dominates CJK extraction cost.
const cjkBenchFixture = "cjk/irs-p850-zh-hant.pdf"

// Throughput baseline only (no ReportAllocs); for alloc tracking see BenchmarkCJKColdOpenExtract.
func BenchmarkCJKGetPlainText(b *testing.B) {
	data, err := os.ReadFile(corpusPath(cjkBenchFixture))
	if err != nil {
		b.Fatalf("read cjk fixture: %v", err)
	}
	r, err := OpenBytes(data)
	if err != nil {
		b.Fatalf("open cjk fixture: %v", err)
	}
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		rd, err := r.GetPlainText(context.Background())
		if err != nil {
			b.Fatal(err)
		}
		_, _ = io.Copy(io.Discard, rd)
	}
}

// BenchmarkCJKColdOpenExtract opens a FRESH Reader every iteration and
// extracts once: the one-shot usage profile. The cache still helps within the
// single extraction (page tree, fonts, and ObjStm payloads are re-dereferenced
// thousands of times per document), but unlike BenchmarkCJKGetPlainText it
// cannot amortize across iterations. Both numbers ship in the archive.
func BenchmarkCJKColdOpenExtract(b *testing.B) {
	data, err := os.ReadFile(corpusPath(cjkBenchFixture))
	if err != nil {
		b.Fatalf("read cjk fixture: %v", err)
	}
	b.ReportAllocs()
	b.ResetTimer()
	for range b.N {
		r, err := OpenBytes(data)
		if err != nil {
			b.Fatal(err)
		}
		rd, err := r.GetPlainText(context.Background())
		if err != nil {
			b.Fatal(err)
		}
		if _, err := io.Copy(io.Discard, rd); err != nil {
			b.Fatal(err)
		}
	}
}

